from __future__ import annotations

import numpy as np

from .models import IntentVector, Session

# Lazy-loaded model to avoid import-time download.
_model = None


def _get_model():
    global _model
    if _model is None:
        from sentence_transformers import SentenceTransformer
        _model = SentenceTransformer("all-MiniLM-L6-v2")
    return _model


def extract_intent(session: Session) -> IntentVector:
    """Extract user intent from session prompts.

    Combines all user prompt texts into a single intent string,
    generates a 384-dim embedding, and returns an IntentVector.
    """
    prompts = session.user_prompts
    if not prompts:
        return IntentVector(
            text="",
            embedding=np.zeros(384),
            confidence=0.0,
            source_prompts=[],
        )

    combined_text = " ".join(prompts)
    model = _get_model()
    embedding = model.encode(combined_text, convert_to_numpy=True)

    confidence = _compute_confidence(prompts)

    return IntentVector(
        text=combined_text,
        embedding=embedding,
        confidence=confidence,
        source_prompts=list(prompts),
    )


def embed_text(text: str) -> np.ndarray:
    """Generate embedding for a single text string."""
    model = _get_model()
    return model.encode(text, convert_to_numpy=True)


def embed_texts(texts: list[str]) -> np.ndarray:
    """Generate embeddings for multiple texts (batched)."""
    if not texts:
        return np.zeros((0, 384))
    model = _get_model()
    return model.encode(texts, convert_to_numpy=True)


def _compute_confidence(prompts: list[str]) -> float:
    """Compute confidence in intent extraction based on prompt quality."""
    if not prompts:
        return 0.0

    combined = " ".join(prompts)
    word_count = len(combined.split())

    # Short/ambiguous prompts get lower confidence.
    if word_count <= 2:
        return 0.3
    if word_count <= 5:
        return 0.5
    if word_count <= 10:
        return 0.7
    return 0.9

